*{
  margin: 0;
  padding: 0;
}
body{
  overflow-x: hidden;
}
.register1{
  color: black !important;
}

@media(max-width:1618px){
  .search {
    display: grid;
    grid-template-columns: repeat(2,1fr);
  }
}
@media(max-width:770px){
  .search {
    display: grid;
    grid-template-columns: repeat(1,1fr);
   
  }
}
 a{
  text-decoration: none !important;
 
}
/* top nav Responsiveness */
@media(max-width:1000px){
  .hideRes {
    display: none;
  }
  .topnavwidth{
   width: auto;
  }
}
.white-background {
background-color: white;
}
/* bottom nav responsiveness */
/* General Styling for Large Screens */
@media (max-width: 1940px) {
  .widthof {
    width: 78vw;
  
  }
} 
input:-webkit-autofill,
textarea:-webkit-autofill,
select:-webkit-autofill {
  background-color: transparent !important;
  color: black !important;
  transition: background-color 5000s ease-in-out 0s;
}

@media (max-width: 1195px) {
  .widthof {
    width: auto;
  }
}

/* Adjusting Bottom Width for Medium Screens */
@media (max-width: 1528px) {
  .bottom {
    width: 97vw;
  }
}

/* Hiding Elements and Adjusting Layout for Small Screens */
@media (max-width: 1268px) {
  .hide {
    display: none;
  }
  .bottom {
    width: 80vw;
  }
  .left-nav {
    font-size: 1.5rem;
    display: flex;
  }
}


@media (max-width: 1730px) {
  .hide {
    display: flex;
  }
  .bottom {
    width: 90vw;
  }
  .left-nav {
    font-size: 1rem;
    display: flex;
  }
}
@media (max-width: 1438px) {

  .left-nav {
    font-size: 1rem;
    display: flex;
  }
}
/* Mobile View: Display Bar and Hide Left Navigation */
@media (max-width: 1095px) {
  .bar {
    display: flex !important;
    justify-content: center;
    align-items: center;
  }
  .left-nav {
    display: none;
  }

}

/* Extra Improvements for Mobile Screens */
@media (max-width: 768px) {
  .bottom {
    padding: 0 10px;
  }
  .widthof {
    width: 90vw;
  }
}

@media (max-width: 480px) {
  .bar {
    flex-direction: column;
    gap: 10px;
  }
}

   
    
/* mobile view styling */
    .offcanvas {
      background-color: rgba(170, 157, 157, 0.753) !important; /* Replace with your desired color */
      color: white;
    }
    .cross {
      color: white !important;
    }
/* icons section */
    .slider-item {
      padding: 0 20px; /* Adjust gap between slides */
    }
    
    .slider-image {
      width: 100%; /* Ensures the images fit within the container */
      object-fit: contain; /* Prevents stretching of images */
    }

    /* animation */
    .animate{
      animation: appear linear;
      animation-timeline: view();
      animation-range: entry 0 cover 40%;
    }
    @keyframes appear {
      from{
        opacity: 0;
        scale: 0.5;
      }
      to {
        opacity: 1;
        scale: 1;
      }
    }

    /* styling for register slider */
    .breadcrumb-wrapper {
      position: relative; /* Needed for the pseudo-element to position properly */
      overflow: hidden; /* Ensures the shimmer stays within the element's boundaries */
      background-color: #A06CD5; /* Placeholder background (light gray) */
    
      padding: 20px; /* Adds some spacing */
     
    }
    
    .breadcrumb-wrapper::before {
      content: '';
      position: absolute;
      top: 0;
      left: -100%; /* Starts completely off-screen to the left */
      width: 100%;
      height: 100%;
      background-image: linear-gradient(
        to right,
        rgba(255, 255, 255, 0.3) 10%, 
        rgba(255, 255, 255, 0) 50%, 
        rgba(255, 255, 255, 0.3) 90%
      );
      background-size: 200% 100%; /* Double the width to allow for smooth sliding */
      animation: slide 3s linear infinite; /* Applies the shimmering animation */
    }
    
    /* Keyframes for the sliding effect */
    @keyframes slide {
      from {
        left: -100%; /* Start off-screen on the left */
      }
      to {
        left: 100%; /* Move off-screen to the right */
      }
    }
